{
  "name": "Vermont Senior Companion Program",
  "eligibility": {
    "age": 55,
    "income_limits": "Based on 200% of federal poverty guidelines. Examples: 2022 levels - $27,180 (1 person), $36,620 (2), $46,060 (3), $55,500 (4); other sources cite approx. $30,120 (single), $40,880 (couple), $51,640 (3), $62,400 (4), or $31,300 (single), $42,300 (couple). Levels updated annually; contact agency for current table.[1][2][4]",
    "asset_limits": "No asset limits mentioned in available information.",
    "other_requirements": ["Able to serve at least 10 hours per week (up to 40 hours)", "Available through Vermont’s Area Agencies on Aging"]
  },
  "benefits": {
    "type": "service",
    "value": "Non-financial assistance and friendship to elderly adults (age 60+) facing difficulty with daily tasks like shopping, paying bills, errands, rides; promotes independence and provides caregiver respite. For companions: $4.00/hour non-taxable stipend (does not affect benefits like 3SquaresVT or housing), $0.70/mile reimbursement, flexible 10-40 hours/week, training (orientation + 4 hours/month in-service), monthly gatherings, support.[1][2]",
    "varies_by": "fixed"
  },
  "application": {
    "methods": ["Contact Area Agencies on Aging: Age Well (www.agewellvt.org), Northeast Kingdom Council on Aging (www.nekcouncil.org), Senior Solutions (www.seniorsolutionsvt.org), Southwestern Vermont Council on Aging (www.svcoa.org)", "Helpline: 1-800-642-5119[2]"],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": ["No specific form names/numbers listed; apply through agencies"],
    "documents": ["Income verification to meet guidelines (exact documents not detailed)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Vermonters statewide via 4 Area Agencies on Aging.",
    "regional_variations": "Administered by 4 regional agencies (Age Well, NEK Council on Aging, Senior Solutions, SVCOA); potential differences in coordinators/training but core program uniform.[1]",
    "offices_or_providers": ["Age Well (www.agewellvt.org)", "Northeast Kingdom Council on Aging (www.nekcouncil.org)", "Senior Solutions (www.seniorsolutionsvt.org)", "Southwestern Vermont Council on Aging (www.svcoa.org)"]
  },
  "official_source": "No single primary .gov URL; program via AmeriCorps Seniors, administered by Vermont Area Agencies on Aging (e.g., www.agewellvt.org).[1][2]",
  "gotchas": ["This is a volunteer program for low-income seniors (55+) to help other elderly; families do not 'qualify' or 'apply' directly for services—their loved one must be matched with a companion volunteer. Income eligibility uses approx. 200% poverty level (updates yearly). Stipend non-taxable and benefit-protected. Not a paid job or direct client service signup.[1][2]", "Income examples from sources vary slightly by year; verify current with agency."],
  "data_shape_notes": "Volunteer companion program (not direct client benefits); eligibility for companions only; income at ~200% FPL with annual updates; statewide via 4 regional agencies; no asset test or client application process."
}
